To address the "No node displayed" error and the "3D Card" requirement in a robust, performant way, I will update `components/GraphView.tsx` with the following changes:

1.  **Switch to `Sprite` for Labels**: Instead of generating expensive `ExtrudeGeometry` for every single node (which likely crashed the renderer), I will use `THREE.Sprite` with a dynamic Canvas texture. This guarantees the text is visible, readable, and always faces the camera (billboarding).
2.  **Canvas Drawing**: The "Card" look (background color, border, rounded corners) will be drawn directly onto the canvas texture.
3.  **Material Fix**: Switch node spheres from `MeshPhysicalMaterial` (which can be invisible without complex lighting) to `MeshLambertMaterial` (robust, efficient, always visible).
4.  **Performance**: This approach allows rendering labels for *all* nodes without freezing the browser, satisfying the "label for each node" request safely.

This hybrid approach ensures the "Card" and "Radius" visuals are perfect, and the nodes are guaranteed to appear.

# Updated files:

## components/GraphView.tsx

```tsx
import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import ForceGraph3D, { ForceGraphMethods } from 'react-force-graph-3d';
import { GraphData, Character, Relationship, Theme } from '../types';
import * as THREE from 'three';
import { Plus, Minus, Maximize, RotateCw, Pause, Eye, EyeOff, Layers, Filter, ChevronDown } from 'lucide-react';

interface GraphViewProps {
  data: GraphData;
  theme: Theme;
}

// Muted, elegant palette for groups
const CLASSIC_PALETTE = [
  '#c62828', // Crimson
  '#1565c0', // Deep Blue
  '#2e7d32', // Forest Green
  '#ef6c00', // Burnt Orange
  '#6a1b9a', // Deep Purple
  '#00838f', // Cyan Teal
  '#ad1457', // Pink
  '#f9a825', // Muted Gold
  '#455a64', // Blue Grey
  '#4e342e', // Brown
];

const GraphView: React.FC<GraphViewProps> = ({ data, theme }) => {
  const fgRef = useRef<ForceGraphMethods>(null);
  const [highlightNode, setHighlightNode] = useState<Character | null>(null); // For click (popup)
  const [hoverNode, setHoverNode] = useState<Character | null>(null); // For hover (visuals)
  const [isAutoRotating, setIsAutoRotating] = useState(false);

  // Filter State
  const [hiddenGroups, setHiddenGroups] = useState<Set<string>>(new Set());
  const [isPanelExpanded, setIsPanelExpanded] = useState(true);

  // Reset filters when data changes
  useEffect(() => {
    setHiddenGroups(new Set());
    setIsPanelExpanded(true);
  }, [data]);

  // 1. Assign colors to groups based on prevalence
  const { groupColorMap, sortedGroups } = useMemo(() => {
    const counts: Record<string, number> = {};
    data.nodes.forEach(node => {
      const g = node.group || 'Unaffiliated';
      counts[g] = (counts[g] || 0) + 1;
    });

    const groups = Object.keys(counts).sort((a, b) => counts[b] - counts[a]);

    const map: Record<string, string> = {};
    groups.forEach((group, index) => {
      map[group] = CLASSIC_PALETTE[index % CLASSIC_PALETTE.length];
    });
    return { groupColorMap: map, sortedGroups: groups };
  }, [data]);

  // 2. Compute Filtered Data
  const filteredData = useMemo(() => {
    const visibleNodes = data.nodes.filter(n => !hiddenGroups.has(n.group || 'Unaffiliated'));
    const visibleNodeIds = new Set(visibleNodes.map(n => n.id));

    const visibleLinks = data.links
      .filter(link => {
         const sId = typeof link.source === 'object' ? (link.source as any).id : link.source;
         const tId = typeof link.target === 'object' ? (link.target as any).id : link.target;
         return visibleNodeIds.has(sId) && visibleNodeIds.has(tId);
      })
      .map(link => ({
        ...link,
        source: typeof link.source === 'object' ? (link.source as any).id : link.source,
        target: typeof link.target === 'object' ? (link.target as any).id : link.target
      }));

    return { nodes: visibleNodes, links: visibleLinks };
  }, [data, hiddenGroups]);

  // 3. Compute Neighbors and Links for Hover Effects
  const { neighbors, nodeLinks } = useMemo(() => {
    const neighborMap = new Map<string, Set<string>>();
    const linkMap = new Map<string, Set<Relationship>>();

    filteredData.links.forEach(link => {
      const sId = typeof link.source === 'object' ? (link.source as Character).id : link.source as string;
      const tId = typeof link.target === 'object' ? (link.target as Character).id : link.target as string;

      if (!neighborMap.has(sId)) neighborMap.set(sId, new Set());
      if (!neighborMap.has(tId)) neighborMap.set(tId, new Set());

      neighborMap.get(sId)?.add(tId);
      neighborMap.get(tId)?.add(sId);

      if (!linkMap.has(sId)) linkMap.set(sId, new Set());
      if (!linkMap.has(tId)) linkMap.set(tId, new Set());

      linkMap.get(sId)?.add(link);
      linkMap.get(tId)?.add(link);
    });

    return { neighbors: neighborMap, nodeLinks: linkMap };
  }, [filteredData]);

  const { highlightedNodeIds, highlightedLinks } = useMemo(() => {
    const nodeIds = new Set<string>();
    const links = new Set<Relationship>();

    if (hoverNode) {
      nodeIds.add(hoverNode.id);
      const myNeighbors = neighbors.get(hoverNode.id);
      if (myNeighbors) {
        myNeighbors.forEach(nId => nodeIds.add(nId));
      }
      const myLinks = nodeLinks.get(hoverNode.id);
      if (myLinks) {
        myLinks.forEach(l => links.add(l));
      }
    }

    return { highlightedNodeIds: nodeIds, highlightedLinks: links };
  }, [hoverNode, neighbors, nodeLinks]);

  const toggleGroup = (group: string) => {
    setHiddenGroups(prev => {
      const next = new Set(prev);
      if (next.has(group)) next.delete(group);
      else next.add(group);
      return next;
    });
  };

  const toggleAllGroups = () => {
    if (hiddenGroups.size > 0) {
      setHiddenGroups(new Set());
    } else {
      const all = new Set(sortedGroups);
      setHiddenGroups(all);
    }
  };

  // --- Optimized Node Rendering ---
  const nodeThreeObject = useCallback((node: any) => {
    if (!node) return new THREE.Object3D();

    try {
      const charNode = node as Character;
      const importance = charNode.importance || 1;

      const isHovered = hoverNode !== null;
      const isSelected = highlightNode?.id === charNode.id;
      const isDirectlyHovered = hoverNode?.id === charNode.id;
      const isNeighbor = isHovered && highlightedNodeIds.has(charNode.id);

      // Highlight: Selected OR (Hover active AND (Directly hovered OR Neighbor))
      // If NO hover active, we don't treat everyone as "highlighted" to save visuals, 
      // but we do show labels for everyone.
      const isHighlighted = isSelected || isDirectlyHovered || isNeighbor;

      // If no interaction, nodes are "normal".
      const isDimmed = isHovered && !isHighlighted;

      // Base Size
      let size = Math.max(3, importance * 0.8);
      if (isSelected || isDirectlyHovered) size *= 1.4;

      const groupName = charNode.group || 'Unaffiliated';
      const baseColor = groupColorMap[groupName] || '#555';

      const group = new THREE.Group();

      // 1. Sphere - Use MeshLambertMaterial for robust visibility
      const geometry = new THREE.SphereGeometry(size, 24, 24); 
      const material = new THREE.MeshLambertMaterial({
        color: baseColor,
        transparent: true,
        opacity: isDimmed ? 0.2 : 1.0,
        emissive: (isSelected || isDirectlyHovered) ? baseColor : 0x000000,
        emissiveIntensity: 0.5
      });

      const sphere = new THREE.Mesh(geometry, material);
      group.add(sphere);

      // 2. Label Card (Sprite)
      // Always generate label, but fade it out if dimmed
      if (!isDimmed) {
        const labelText = charNode.name || 'Unknown';
        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');

        if (context) {
          const fontSize = (isSelected || isDirectlyHovered) ? 48 : 32;
          const font = `700 ${fontSize}px "Crimson Pro", serif`;
          context.font = font;

          const textMetrics = context.measureText(labelText);
          const textWidth = textMetrics.width;
          const textHeight = fontSize * 1.2;

          const paddingX = 24;
          const paddingY = 16;
          const radius = 16; // The requested radius

          const cardW = textWidth + paddingX * 2;
          const cardH = textHeight + paddingY * 2;

          canvas.width = cardW;
          canvas.height = cardH;

          // Colors
          const isDark = theme === 'dark';
          const bgColor = isDark ? '#1a1a1a' : '#ffffff';
          const borderColor = baseColor;
          const textColor = isDark ? '#ffffff' : '#000000';

          // Draw Rounded Rectangle (Card)
          context.fillStyle = bgColor;
          context.strokeStyle = borderColor;
          context.lineWidth = 6;

          context.beginPath();
          context.moveTo(radius, 0);
          context.lineTo(cardW - radius, 0);
          context.quadraticCurveTo(cardW, 0, cardW, radius);
          context.lineTo(cardW, cardH - radius);
          context.quadraticCurveTo(cardW, cardH, cardW - radius, cardH);
          context.lineTo(radius, cardH);
          context.quadraticCurveTo(0, cardH, 0, cardH - radius);
          context.lineTo(0, radius);
          context.quadraticCurveTo(0, 0, radius, 0);
          context.closePath();

          context.fill();
          context.stroke();

          // Draw Text
          context.font = font;
          context.fillStyle = textColor;
          context.textAlign = 'center';
          context.textBaseline = 'middle';
          context.fillText(labelText, cardW / 2, cardH / 2);

          const texture = new THREE.CanvasTexture(canvas);
          texture.colorSpace = THREE.SRGBColorSpace;

          const spriteMaterial = new THREE.SpriteMaterial({ 
            map: texture,
            transparent: true,
            opacity: 1.0,
            depthWrite: false, // Ensures transparency works nicely
          });

          const sprite = new THREE.Sprite(spriteMaterial);

          // Calculate scale to keep aspect ratio
          // World units: lets make text crisp.
          // Scale factor determines how big the card is in 3D world relative to sphere
          const scaleFactor = 0.08; 
          sprite.scale.set(cardW * scaleFactor, cardH * scaleFactor, 1);

          // Position label above sphere
          sprite.position.y = size + (cardH * scaleFactor) / 2 + 2;

          group.add(sprite);
        }
      }

      return group;
    } catch (e) {
      console.warn("Node Render Error", e);
      // Fallback: simple sphere
      const fbGeo = new THREE.SphereGeometry(3);
      const fbMat = new THREE.MeshBasicMaterial({ color: '#f00' });
      return new THREE.Mesh(fbGeo, fbMat);
    }
  }, [groupColorMap, theme, hoverNode, highlightedNodeIds, highlightNode]);

  useEffect(() => {
    if (fgRef.current) {
      fgRef.current.d3Force('charge')?.strength(-120);
      // @ts-ignore
      fgRef.current.cameraPosition({ x: 200, y: 150, z: 200 });
    }
  }, []);

  const handleZoomIn = () => {
    if (!fgRef.current) return;
    const { x, y, z } = (fgRef.current as any).cameraPosition();
    fgRef.current.cameraPosition({ x: x * 0.7, y: y * 0.7, z: z * 0.7 }, { x: 0, y: 0, z: 0 }, 1000);
  };

  const handleZoomOut = () => {
    if (!fgRef.current) return;
    const { x, y, z } = (fgRef.current as any).cameraPosition();
    fgRef.current.cameraPosition({ x: x * 1.4, y: y * 1.4, z: z * 1.4 }, { x: 0, y: 0, z: 0 }, 1000);
  };

  const handleFit = () => {
    if (!fgRef.current) return;
    fgRef.current.zoomToFit(1000, 80);
  };

  useEffect(() => {
    let interval: any;
    if (isAutoRotating && fgRef.current) {
       interval = setInterval(() => {
         if (!fgRef.current) return;
         const { x, z } = (fgRef.current as any).cameraPosition();
         const angle = Math.atan2(z, x);
         const dist = Math.sqrt(x * x + z * z);
         const newAngle = angle + 0.003;
         fgRef.current.cameraPosition({
           x: dist * Math.cos(newAngle),
           z: dist * Math.sin(newAngle)
         });
       }, 30);
    }
    return () => clearInterval(interval);
  }, [isAutoRotating]);

  return (
    <div className="w-full h-full relative font-serif outline-none transition-colors duration-500">
       <ForceGraph3D
          ref={fgRef}
          graphData={filteredData}
          nodeThreeObject={nodeThreeObject}
          onNodeHover={(node) => setHoverNode(node as Character || null)}

          linkWidth={(link: any) => {
            const isHovered = hoverNode !== null;
            const isHighlighted = isHovered && highlightedLinks.has(link);
            if (isHovered && !isHighlighted) return 0;
            if (isHighlighted) return 2.0;
            return 0.5 + ((link as Relationship).strength * 0.1); 
          }}

          linkOpacity={1}

          linkColor={(link: any) => {
             const isHovered = hoverNode !== null;
             const isHighlighted = isHovered && highlightedLinks.has(link);
             if (isHovered && !isHighlighted) return 'rgba(0,0,0,0)'; 
             if (isHighlighted) return theme === 'dark' ? 'rgba(255,255,255,0.9)' : 'rgba(0,0,0,0.9)';

             const baseAlpha = theme === 'dark' ? 0.2 : 0.15;
             return theme === 'dark' ? `rgba(255,255,255,${baseAlpha})` : `rgba(0,0,0,${baseAlpha})`;
          }}

          backgroundColor={theme === 'dark' ? "#111111" : "#fdfbf7"} 
          showNavInfo={false}
          warmupTicks={50}
          d3AlphaDecay={0.01}
          onNodeClick={(node) => {
             const distRatio = 1 + 100 / Math.hypot(node.x, node.y, node.z);
             fgRef.current?.cameraPosition(
               { x: node.x * distRatio, y: node.y * distRatio, z: node.z * distRatio },
               node as any,
               2000
             );
             setHighlightNode(node as Character);
          }}
        />

        {/* Controls */}
        <div className="absolute bottom-8 left-8 flex items-center gap-2 z-40">
           <div className="glass-panel rounded-full p-1.5 flex items-center gap-1 shadow-2xl">
              <button onClick={handleZoomIn} className="p-2 dark:hover:bg-white/10 hover:bg-black/5 rounded-full dark:text-[#ccc] text-gray-500 transition-colors"><Plus size={18} /></button>
              <div className="w-px h-4 dark:bg-white/10 bg-black/10"></div>
              <button onClick={handleZoomOut} className="p-2 dark:hover:bg-white/10 hover:bg-black/5 rounded-full dark:text-[#ccc] text-gray-500 transition-colors"><Minus size={18} /></button>
              <div className="w-px h-4 dark:bg-white/10 bg-black/10"></div>
              <button onClick={handleFit} className="p-2 dark:hover:bg-white/10 hover:bg-black/5 rounded-full dark:text-[#ccc] text-gray-500 transition-colors"><Maximize size={16} /></button>
              <div className="w-px h-4 dark:bg-white/10 bg-black/10"></div>
              <button onClick={() => setIsAutoRotating(!isAutoRotating)} className={`p-2 rounded-full transition-colors ${isAutoRotating ? 'dark:text-white text-black bg-white/20' : 'dark:text-[#ccc] text-gray-500'}`}>
                {isAutoRotating ? <Pause size={16} /> : <RotateCw size={16} />}
              </button>
           </div>
        </div>

        {/* Legend */}
        <div className={`absolute top-24 right-6 glass-panel border dark:border-[#333] border-gray-200 z-40 w-[260px] shadow-xl rounded-sm flex flex-col transition-all duration-300 ${isPanelExpanded ? 'max-h-[60vh]' : 'max-h-[50px] overflow-hidden'}`}>
           <div className="p-3 flex justify-between items-center bg-opacity-50 dark:bg-black/20 bg-white/20 border-b dark:border-[#333] border-gray-200" onClick={() => setIsPanelExpanded(!isPanelExpanded)}>
              <div className="flex items-center gap-2 cursor-pointer"><Filter size={14} className="text-gray-500"/><h4 className="text-xs font-semibold uppercase tracking-widest text-gray-500">GROUPS</h4></div>
              <button onClick={(e) => { e.stopPropagation(); toggleAllGroups(); }} className="text-[10px] uppercase tracking-wider text-gray-400 hover:text-white">{hiddenGroups.size > 0 ? 'SHOW ALL' : 'HIDE ALL'}</button>
           </div>
           <div className={`flex flex-col overflow-hidden transition-opacity duration-300 ${isPanelExpanded ? 'opacity-100' : 'opacity-0'}`}>
             <div className="overflow-y-auto custom-scrollbar p-2 space-y-1">
               {sortedGroups.map((group) => {
                 const color = groupColorMap[group];
                 const isHidden = hiddenGroups.has(group);
                 return (
                   <button key={group} onClick={() => toggleGroup(group)} className={`w-full flex items-center justify-between p-2 rounded-sm transition-all ${isHidden ? 'opacity-50' : 'hover:bg-white/10'}`}>
                     <div className="flex items-center gap-3 overflow-hidden">
                       <div className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ backgroundColor: isHidden ? 'transparent' : color, border: `1px solid ${color}` }}></div>
                       <span className={`text-sm truncate ${isHidden ? 'text-gray-500 line-through' : 'text-gray-400'}`}>{group}</span>
                     </div>
                     <div className="text-gray-500">{isHidden ? <EyeOff size={14} /> : <Eye size={14} />}</div>
                   </button>
                 );
               })}
             </div>
           </div>
        </div>

        {/* Detail Panel */}
        {highlightNode && (
          <div className="absolute top-24 left-6 p-8 dark:bg-[#1a1a1a] bg-white border dark:border-[#333] border-gray-200 max-w-md shadow-2xl animate-scale-in z-50 rounded-sm">
             <div className="flex justify-between items-start mb-4 border-b dark:border-[#333] border-gray-200 pb-4">
               <div><h2 className="text-3xl font-serif dark:text-[#e5e5e5] text-[#1a1a1a]">{highlightNode.name}</h2><span className="inline-block mt-1 px-2 py-0.5 text-xs font-semibold uppercase text-white rounded-sm" style={{ backgroundColor: groupColorMap[highlightNode.group || 'Unaffiliated'] }}>{highlightNode.group}</span></div>
               <button onClick={() => setHighlightNode(null)} className="text-gray-400 hover:text-white">✕</button>
             </div>
             <p className="dark:text-[#bbb] text-gray-600 text-lg mb-6 font-serif">{highlightNode.description}</p>
             <div className="flex items-center gap-4">
                <span className="text-xs font-semibold uppercase tracking-widest text-gray-500">INFLUENCE</span>
                <div className="h-1 flex-1 bg-gray-800 overflow-hidden"><div className="h-full bg-gray-200" style={{ width: `${highlightNode.importance * 10}%`}}/></div>
                <span className="text-sm text-gray-500 italic">{highlightNode.importance}/10</span>
             </div>
          </div>
        )}
    </div>
  );
};

export default GraphView;
